    static func search(query: String) -> [WorkoutSplit] {
        guard !query.isEmpty else { return all }
        let q = query.lowercased()
        return all.filter {
            $0.title.lowercased().contains(q) ||
            $0.tags.contains(where: { $0.contains(q) }) ||
            $0.goals.contains(where: { $0.lowercased().contains(q) }) ||
            $0.inspiredBy.lowercased().contains(q) ||
            $0.workouts.contains(where: { $0.exercises.contains(where: { $0.name.lowercased().contains(q) }) })
        }
    }
